  `hour_is_day` tinyint DEFAULT NULL,
  `hour_condition_text` varchar(255) DEFAULT NULL,
  `hour_condition_icon` varchar(255) DEFAULT NULL,
  `hour_condition_code` int DEFAULT NULL,
  `hour_wind_mph` decimal(5,2) DEFAULT NULL,
  `hour_wind_kph` decimal(5,2) DEFAULT NULL,
  `hour_wind_degree` int DEFAULT NULL,
  `hour_wind_dir` varchar(50) DEFAULT NULL,
  `hour_pressure_mb` decimal(6,1) DEFAULT NULL,
  `hour_pressure_in` decimal(5,2) DEFAULT NULL,
  `hour_precip_mm` decimal(6,2) DEFAULT NULL,
  `hour_precip_in` decimal(5,2) DEFAULT NULL,
  `hour_snow_cm` decimal(5,2) DEFAULT NULL,
  `hour_humidity` int DEFAULT NULL,
  `hour_cloud` int DEFAULT NULL,
  `hour_feelslike_c` decimal(5,2) DEFAULT NULL,
  `hour_feelslike_f` decimal(5,2) DEFAULT NULL,
  `hour_windchill_c` decimal(5,2) DEFAULT NULL,
  `hour_windchill_f` decimal(5,2) DEFAULT NULL,
  `hour_heatindex_c` decimal(5,2) DEFAULT NULL,
  `hour_heatindex_f` decimal(5,2) DEFAULT NULL,
  `hour_dewpoint_c` decimal(5,2) DEFAULT NULL,
  `hour_dewpoint_f` decimal(5,2) DEFAULT NULL,
  `hour_will_it_rain` tinyint DEFAULT NULL,
  `hour_chance_of_rain` int DEFAULT NULL,
  `hour_will_it_snow` tinyint DEFAULT NULL,
  `hour_chance_of_snow` int DEFAULT NULL,
  `hour_vis_km` decimal(5,2) DEFAULT NULL,
  `hour_vis_miles` decimal(5,2) DEFAULT NULL,
  `hour_gust_mph` decimal(5,2) DEFAULT NULL,
  `hour_gust_kph` decimal(5,2) DEFAULT NULL,
